# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, render_template, request
import cgi

app = Flask(__name__)

@app.route('/welcome')
def welcome_dashboard():
    user_name = request.args.get('name', 'Guest')
    user_bio = request.args.get('bio', 'No bio provided.')
    user_location = request.args.get('location', 'Unknown')
    user_status = request.args.get('status', 'Online')

    # Sanitize inputs for HTML rendering, then allow specific formatting
    # This approach is simple but for production, a more robust markdown/BBCode parser
    # and a stricter sanitizer like bleach would be recommended.
    
    # First, escape all HTML characters to prevent XSS
    sanitized_name = cgi.escape(user_name)
    sanitized_location = cgi.escape(user_location)

    # For bio and status, we want to allow specific tags like <b> and <i>
    # We'll escape everything first, then carefully re-introduce allowed formatting.
    # This is a very basic example and not a robust solution for untrusted input.
    # A better approach would be to use a library like Bleach.
    
    # Example of a very basic "allow list" processing:
    processed_bio = cgi.escape(user_bio)
    processed_bio = processed_bio.replace('&lt;b&gt;', '<b>').replace('&lt;/b&gt;', '</b>')
    processed_bio = processed_bio.replace('&lt;i&gt;', '<i>').replace('&lt;/i&gt;', '</i>')
    processed_bio = processed_bio.replace('&lt;em&gt;', '<em>').replace('&lt;/em&gt;', '</em>')
    processed_bio = processed_bio.replace('&lt;strong&gt;', '<strong>').replace('&lt;/strong&gt;', '</strong>')
    
    processed_status = cgi.escape(user_status)
    processed_status = processed_status.replace('&lt;b&gt;', '<b>').replace('&lt;/b&gt;', '</b>')
    processed_status = processed_status.replace('&lt;i&gt;', '<i>').replace('&lt;/i&gt;', '</i>')
    processed_status = processed_status.replace('&lt;em&gt;', '<em>').replace('&lt;/em&gt;', '</em>')
    processed_status = processed_status.replace('&lt;strong&gt;', '<strong>').replace('&lt;/strong&gt;', '</strong>')

    return render_template(
        'welcome_dashboard.html',
        name=sanitized_name,
        bio=processed_bio,
        location=sanitized_location,
        status=processed_status
    )

if __name__ == '__main__':
    app.run(debug=True)

